// Calcular AQI des de PM2.5 (EPA)
function calcAQI(pm) {
    const breakpoints = [
        [0, 12, 0, 50],
        [12.1, 35.4, 51, 100],
        [35.5, 55.4, 101, 150],
        [55.5, 150.4, 151, 200],
        [150.5, 250.4, 201, 300],
        [250.5, 500, 301, 500]
    ];

    for (let [cLow, cHigh, iLow, iHigh] of breakpoints) {
        if (pm >= cLow && pm <= cHigh) {
            return Math.round(((iHigh - iLow) / (cHigh - cLow)) * (pm - cLow) + iLow);
        }
    }
    return 500; // Hazardous
}

let pm25 = msg.payload.concentrations_ugm3.pm2_5_standard;
msg.payload.aqi = calcAQI(pm25);
msg.payload.aqi_level = msg.payload.aqi <= 50 ? "Good" : 
                        msg.payload.aqi <= 100 ? "Moderate" : 
                        msg.payload.aqi <= 150 ? "Unhealthy (sensitive)" : "Unhealthy";

return msg;

function calcAQI_PM25(pm) {
    const bp = [
        [0, 12, 0, 50],
        [12.1, 35.4, 51, 100],
        [35.5, 55.4, 101, 150],
        [55.5, 150.4, 151, 200],
        [150.5, 250.4, 201, 300],
        [250.5, 500, 301, 500]
    ];
    return calcFromBreakpoints(pm, bp);
}

function calcAQI_PM10(pm) {
    const bp = [
        [0, 54, 0, 50],
        [55, 154, 51, 100],
        [155, 254, 101, 150],
        [255, 354, 151, 200],
        [355, 424, 201, 300],
        [425, 604, 301, 500]
    ];
    return calcFromBreakpoints(pm, bp);
}

function calcFromBreakpoints(pm, bp) {
    for (let [cLow, cHigh, iLow, iHigh] of bp) {
        if (pm >= cLow && pm <= cHigh) {
            return Math.round(((iHigh - iLow) / (cHigh - cLow)) * (pm - cLow) + iLow);
        }
    }
    return 500;
}

// CALCULAR AQI COMBINAT
let pm25 = msg.payload.concentrations_ugm3.pm2_5_standard;
let pm10 = msg.payload.concentrations_ugm3.pm10_standard;

let aqi25 = calcAQI_PM25(pm25);
let aqi10 = calcAQI_PM10(pm10);

msg.payload.aqi = Math.max(aqi25, aqi10); // EL PITJOR!
msg.payload.aqi_level = msg.payload.aqi <= 50 ? "Good" : 
                        msg.payload.aqi <= 100 ? "Moderate" : "Unhealthy";

return msg;

try {
    // Attempt to parse the file as JSON
    const creds = JSON.parse(msg.payload);

    global.set("device_auth_token", creds.token);
    global.set("device_id", creds.device_id);
    global.set("nickname", creds.nickname);

    msg.payload = `✅ Active: ${creds.nickname} (${creds.device_id})`;
    node.status({fill:"green", shape:"dot", text:"Authenticated"});
} catch (e) {
    // FALLBACK: If the file is just the old raw token string
    global.set("device_auth_token", msg.payload);
    msg.payload = "⚠️ Token loaded, but nickname missing. Please re-register.";
    node.status({fill:"yellow", shape:"ring", text:"Legacy Token"});
}
return msg;

const token = global.get("device_auth_token");
const nickname = global.get("nickname");

// Ensure token is a clean string and trim any accidental whitespace
const cleanToken = String(token).trim();

msg.headers = {
    "Authorization": "Bearer " + cleanToken,
    "Content-Type": "application/json"
};

// Ensure the URL has NO leading/trailing spaces
msg.url = "https://data.schoolair.org/node/aqc/v1/ingest";

// Optional: Add nickname to payload
if (nickname) {
    msg.payload.nickname = nickname;
}

return msg;

const serial = global.get("cpu_serial");
const nickname = msg.payload.nickname; // Capture it here

msg.headers = {
    "Authorization": "Bearer " + msg.payload.org_token,
    "Content-Type": "application/json"
};

// Store nickname in the top-level msg object so it survives the HTTP call
msg.nickname = nickname;

msg.payload = {
    cpu_serial: serial,
    nickname: nickname
};

return msg;

// msg.payload comes from your Server Success Handler
// It contains { status: "success", token: "...", device_id: "..." }

msg.payload = JSON.stringify({
    token: msg.payload.token,       // CHANGED FROM auth_token TO token
    device_id: msg.payload.device_id,
    nickname: msg.nickname          // Carried over from the form submission
});

return msg;

// 1. Save Device ID to global context
global.set("device_id", msg.payload.device_id);

// 2. Save Nickname to global context (This is the missing piece!)
// We get it from the original registration request data
if (msg.nickname) {
    global.set("nickname", msg.nickname);
}

// 3. Prepare the UI feedback
if (msg.payload.new_registration) {
    msg.payload = "🎉 " + (msg.nickname || "Device") + " was added successfully!";
} else {
    msg.payload = "👋 Welcome Back! Connection restored.";
}

return msg;

try {
    // Parse the string from the File node
    msg.sen6x = JSON.parse(msg.payload);

} 
catch (error) {
    // If the file was empty or corrupted during a write, catch the error
    msg.sen6x = {};
}

delete msg.payload;
return msg;

msg.payload = {
    timestamp: new Date().toISOString(),
    sen6x: msg.sen6x || {},
    mgs: msg.mgs || {}
}
return msg;

try {
    // Parse the string from the File node
    msg.mgs = JSON.parse(msg.payload);
} 
catch (error) {
    // If the file was empty or corrupted during a write, catch the error
    msg.mgs = {};
}

delete msg.payload;
return msg;

// Parse nmcli output - Fixed for exec output
const output = msg.payload.stdout || msg.payload;
const lines = output.trim().split('\n');

// Skip header
const networks = [];
for (let i = 1; i < lines.length; i++) {
    const line = lines[i].trim();
    if (!line) continue;

    // Split by multiple spaces
    const parts = line.split(/\s{2,}/);

    if (parts.length >= 2) {
        const ssid = parts[0].trim();
        const signal = parseInt(parts[1]) || 0;
        const security = parts.length > 2 && parts[2].trim() !== '--';

        // Avoid empty SSIDs and duplicates
        if (ssid && !networks.find(n => n.ssid === ssid)) {
            networks.push({
                ssid: ssid,
                signal: signal,
                security: security
            });
        }
    }
}

// Sort by signal strength
networks.sort((a, b) => b.signal - a.signal);

msg.payload = {
    networks: networks
};

msg.headers = {
    'Content-Type': 'application/json'
};

return msg;

const ssid = msg.payload.ssid;
const password = msg.payload.password;

if (!ssid) {
    msg.payload = {
        success: false,
        error: "SSID required"
    };
    return msg;
}

// Build nmcli command
if (password && password.length > 0) {
    // Network with password
    msg.payload = `nmcli device wifi connect "${ssid}" password "${password}"`;
} else {
    // Open network
    msg.payload = `nmcli device wifi connect "${ssid}"`;
}

// Save data for response
msg.ssid = ssid;

return msg;

const exitCode = msg.payload.code || 0;
const stderr = msg.payload.stderr || '';
const stdout = msg.payload.stdout || '';

if (exitCode === 0) {
    msg.payload = {
        success: true,
        message: `Connected to ${msg.ssid}`,
        ssid: msg.ssid
    };
} else {
    msg.payload = {
        success: false,
        error: stderr || stdout || "Unknown error"
    };
}

msg.statusCode = 200;
msg.headers = {
    'Content-Type': 'application/json'
};

return msg;

// Parse WiFi status from first command
const wifiOutput = msg.payload.stdout || '';
const lines = wifiOutput.trim().split('\n');

let connected = false;
let ssid = '';
let wifiIP = '';

// Parse nmcli output
lines.forEach(line => {
    if (line.includes('GENERAL.CONNECTION:')) {
        ssid = line.split(':')[1].trim();
        if (ssid && ssid !== '--') {
            connected = true;
        }
    }
    if (line.includes('IP4.ADDRESS[1]:')) {
        wifiIP = line.split(':')[1].trim().split('/')[0];
    }
});

// Get ethernet IP from context (passed through from previous exec)
let ethernetIP = '';
const ethOutput = msg.payload.stdout || '';
if (ethOutput.includes('IP4.ADDRESS')) {
    const ethLines = ethOutput.trim().split('\n');
    ethLines.forEach(line => {
        if (line.includes('IP4.ADDRESS')) {
            ethernetIP = line.split(':')[1].trim().split('/')[0];
        }
    });
}

msg.payload = {
    connected: connected,
    ssid: ssid || null,
    wifiIP: wifiIP || null,
    ethernetIP: ethernetIP || null
};

msg.headers = {
    'Content-Type': 'application/json'
};

return msg;

const exitCode = msg.payload.code || 0;
const stderr = msg.payload.stderr || '';
const stdout = msg.payload.stdout || '';

if (exitCode === 0) {
    msg.payload = {
        success: true,
        message: 'Disconnected from WiFi'
    };
} else {
    msg.payload = {
        success: false,
        error: stderr || stdout || 'Unknown error'
    };
}

msg.statusCode = 200;
msg.headers = {
    'Content-Type': 'application/json'
};

return msg;

const output = msg.payload.stdout || '';
const lines = output.trim().split('\n');

const networks = [];

lines.forEach(line => {
    if (!line) return;

    const parts = line.split(':');
    if (parts.length >= 2) {
        const name = parts[0].trim();
        const type = parts[1].trim();

        // Only include WiFi connections (802-11-wireless)
        if (type === '802-11-wireless' && name) {
            networks.push(name);
        }
    }
});

msg.payload = {
    networks: networks
};

msg.headers = {
    'Content-Type': 'application/json'
};

return msg;

const ssid = msg.payload.ssid;
const password = msg.payload.password;

// We use --wait 15 so it doesn't block Node-RED forever
if (password && password.length > 0) {
    msg.payload = `sudo nmcli device wifi connect "${ssid}" password "${password}" --wait 15`;
} else {
    msg.payload = `sudo nmcli device wifi connect "${ssid}" --wait 15`;
}

msg.ssid = ssid;
return msg;
